// ─── HISTORICAL TIER LOOKUP ───────────────────────────────────────────────────
// eventDateStr: 'YYYY-MM' or 'YYYY-MM-DD' — finds the fighter's rank as of that month
export const getHistoricalTier = (fighterName, eventDateStr) => {
  const entries = HISTORICAL_RANKINGS[fighterName];
  if (!entries || !entries.length) return 0.12;
  const s = eventDateStr.replace(/-/g,'');
  const eventYM = parseInt(s.slice(0,6));
  if (isNaN(eventYM)) return 0.12;
  let lo = 0, hi = entries.length - 1, best = null;
  while (lo <= hi) {
    const mid = (lo + hi) >> 1;
    if (entries[mid][0] <= eventYM) { best = entries[mid]; lo = mid + 1; }
    else hi = mid - 1;
  }
  if (!best) return 0.12;
  const rank = best[1];
  if (rank === 0) return 1.0;
  return Math.max(0.42, 0.93 * Math.exp(-0.037 * (rank - 1)));
};